document.addEventListener("DOMContentLoaded", function () {

    const element = document.querySelector('.welcome-text-type');

    if (typeof Typed !== 'undefined' && element) {

        const strings = element
            .getAttribute('data-options')
            .split(',')
            .map(item => item.trim());

        new Typed('.welcome-text-type', {
            strings: strings,

            typeSpeed: 60,
            backSpeed: 35,
            backDelay: 1800,

            smartBackspace: true,
            loop: true,

            showCursor: true,
            cursorChar: '│'
        });
    }
});